#include <bits/stdc++.h>
using namespace std;

string solve(string path) {
    // Initial position and direction
    int x = 0, y = 0;
    int dir = 0;  // 0:North, 1:East, 2:South, 3:West

    for(char move : path) {
        if(move == 'R') {
            dir = (dir + 1) % 4;
        }
        else if(move == 'L') {
            dir = (4 + dir - 1) % 4;  // Add 4 to handle negative
        }
        else {  // move == 'G'
            switch(dir) {
                case 0: y++; break;  // North
                case 1: x++; break;  // East
                case 2: y--; break;  // South
                case 3: x--; break;  // West
            }
        }
    }

    return (x == 0 && y == 0) ? "YES" : "NO";
}

int main() {
    string path;
    cin >> path;
    cout << solve(path) << endl;
    return 0;
}
